import React, { useEffect } from 'react';
// import AOS from 'aos';
import 'aos/dist/aos.css';

const Hero = () => {

  return (
    <section id="hero" class="hero section light-background">

      <img src={`${process.env.PUBLIC_URL}/static/media/img/5651978.png`} alt="/"></img>

      <div class="container aos-init aos-animate" data-aos="zoom-out">
        <div class="row justify-content-center">
          <div class="col-lg-9">
            <h2>Deepak Aruldoss</h2>
            <p class="my-designation">I'm <span class="typed">Senior Software Developer</span></p>
            <p class="my-short-intro">As a dedicated Software Backend Developer with over 6 years of experience, I specialize in crafting robust and
            scalable backend solutions. My expertise encompasses a wide range of technologies, including Content
            Management Systems (CMS), Enterprise Resource Planning (ERP) systems, and e-commerce platforms like Shopware
            5 &amp; 6. I have a proven track record of successfully integrating various payment APIs and customizing Odoo
            ERP to meet specific business requirements. I thrive on tackling complex technical challenges and delivering
            efficient solutions tailored to diverse business needs.</p>
            <div class="social-links">
              <a href="https://www.linkedin.com/in/deepak-aruldoss-40426b218" target='_blank'><i class="bi bi-linkedin"></i></a>
              <a href="https://wa.me/6383331367?text=Hi%20Deepak%2C%20I%20would%20like%20to%20connect!" target='_blank'><i class="bi bi-whatsapp"></i></a>
              <a href="#"><i class="bi bi-github"></i></a>
              <a href="#"><i class="bi bi-download"></i></a>

            </div>
          </div>
        </div>
      </div>

    </section>
  );
};

export default Hero;
